        if "platform.basic" not in cls._definitions:
            cls.register(
                EditorObjectDefinition(
                    type_id="platform.basic",
                    label="Platform",
                    category="platform",
                    factory_type="platform",
                    defaults={"width": 240, "height": 40, "z_index": 2}
