            except Exception as e:
                print(f"⚠️ [EditorRegistry] 적 폴더 스캔 중 오류 발생: {e}")
        else:
            # 폴더를 찾을 수 없는 경우를 대비한 비상 안전 폴백 (더미 기본 등록)
